allow:
Bash(powershell -Command "
\\$timeout = 120
\\$elapsed = 0
do {
    Start-Sleep -Seconds 5
    \\$elapsed += 5
    \\$result = docker info 2>&1
    if \(\\$result -match 'Server Version'\) { Write-Output 'Docker ready'; break }
    Write-Output \\"Waiting... \\$elapsed s\\"
} while \(\\$elapsed -lt \\$timeout\)
if \(\\$elapsed -ge \\$timeout\) { Write-Output 'Timeout waiting for Docker' }
" 2>&1)
